impl Span {
    pub fn new(name: impl Into<String>) -> Self {
        Self {
            name: name.into(),
            start: SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs(),
            duration: None,
            attributes: HashMap::new(),
        }
    }

    pub fn with_attribute(mut self, key: impl Into<String>, value: impl Into<String>) -> Self {
        self.attributes.insert(key.into(), value.into());
        self
    }

    pub fn end(&mut self) {
        self.duration = Some(self.start.elapsed().unwrap());
    }

    pub fn duration(&self) -> Option<Duration> {
        self.duration
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

/// 追踪器
#[derive(Debug, Default)]
pub struct Tracer {
    spans: Vec<Span>,
}

impl Tracer {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn start_span(&mut self, name: impl Into<String>) -> &mut Span {
        self.spans.push(Span::new(name));
        self.spans.last_mut().unwrap()
    }

    pub fn spans(&self) -> &[Span] {
        &self.spans
    }

    pub fn completed_spans(&self) -> Vec<&Span> {
        self.spans.iter().filter(|s| s.duration.is_some()).collect()
    }
}

